SELECT venue_id, COUNT(*) AS num_check_ins
FROM venue_check_ins
GROUP BY venue_id;

SELECT COUNT(*) AS total_check_ins
FROM venue_check_ins
WHERE venue_id = 0;

SELECT venue_id, COUNT(event_id) AS event_count
FROM venue_events
GROUP BY venue_id;

SELECT COUNT(like_id)
FROM venue_reviews_likes
WHERE user_id = (SELECT user_id FROM users WHERE email = 'jane.doe@example.com');

SELECT user_id, COUNT(*) AS like_count
FROM venue_reviews_likes
GROUP BY user_id;

SELECT venues.venue_name, venue_categories.category_name
FROM venues 
JOIN venue_categories ON venues.category = venue_categories.category_id;

SELECT AVG(offer_count) 
FROM (
    SELECT venue_id, COUNT(offer_id) AS offer_count 
    FROM venue_offers 
    GROUP BY venue_id
);

SELECT event_id, venue_id, event_name, event_date
FROM venue_events
ORDER BY event_date DESC;

SELECT AVG(r.rating) AS AverageRating
FROM ratings r
JOIN venue_maps vm ON r.venue_id = vm.venue_id;
